def title_words(s):
    words = s.split()
    for i, word in enumerate(words):
        if not word.isupper():
            words[i] = word.capitalize()
    return ' '.join(words)

# Edge case: it handles strings with a mix of uppercase and lowercase words, such as "Hello World" which returns "Hello World" instead of "Hello world".
